const body = $json;
if (body.benefit_type !== 'Tender_complexity_score') return [{ json: { success: false, error_code: 'INVALID_INPUT', message: 'benefit_type must be Tender_complexity_score' } }];
const customizationRatio = Number(body.answers.customization_ratio ?? body.answers.question_1 ?? 0);
const numberOfVariants = Number(body.answers.number_of_variants ?? body.answers.question_2 ?? 0);
const reviewCycles = Number(body.answers.technical_review_cycles ?? body.answers.question_3 ?? 0);
const bidTime = Number(body.answers.bid_submission_time ?? body.answers.question_4 ?? 0);
if (![customizationRatio, numberOfVariants, reviewCycles, bidTime].every(Number.isFinite)) {
  return [{ json: { success: false, error_code: 'INVALID_INPUT', message: 'Complexity metrics must be numeric' } }];
}
return [{ json: { ...body, complexity_inputs: { customizationRatio, numberOfVariants, reviewCycles, bidTime } } }];

if ($json.success === false) return [{ json: $json }];
const { customizationRatio, numberOfVariants, reviewCycles, bidTime } = $json.complexity_inputs;
const complexity_index = Math.max(0, Math.min(100, Math.round((customizationRatio * 0.35) + (numberOfVariants * 1.5) + (reviewCycles * 8) + (bidTime * 0.6))));
const risk_level = complexity_index >= 75 ? 'High' : complexity_index >= 40 ? 'Medium' : 'Low';
return [{ json: { ...$json, score: complexity_index, risk_level } }];

if ($json.success === false) return [{ json: $json }];
return [{
  json: {
    success: true,
    benefit_type: 'Tender_complexity_score',
    score: $json.score,
    summary: `Tender complexity index is ${$json.score} (${ $json.risk_level } risk).`,
    recommendations: [
      'Use reusable response modules for recurring compliance sections.',
      'Run early technical risk triage for high-customization opportunities.',
      'Set go/no-go thresholds based on complexity and margin.'
    ],
    meta: {
      execution_id: $execution.id,
      version: '1.0.0',
      benefit_version: '2026-Q1',
      complexity_index: $json.score,
      risk_level: $json.risk_level
    }
  }
}];
